  ('judicial-0b5ab5d8-moex-00086', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-57eacf76', 'sub-judicial-0b5ab5d8-03', NULL, 'essay', '債務人甲之金錢債權人乙聲請強制執行甲所有之A地，甲之其他金錢債
權人丙及丁分別聲明參與分配。執行法院將 A 地拍賣所得價金新臺幣
（下同）300 萬元，按乙、丙、丁所申報之債權額（均為 200 萬元），各
分配 100 萬元。乙主張丙之債權為假債權，依法提起分配表異議之訴，
而獲勝訴判決確定。執行法院應如何重新分配？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "4d4a6be888fe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0411", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00087', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-57eacf76', 'sub-judicial-0b5ab5d8-03', NULL, 'essay', '勞工甲因認雇主乙違法解僱，訴請確認甲、乙間僱傭關係存在，並聲請
在本案判決確定前乙應繼續僱用甲之定暫時狀態處分。法院裁定准許甲
之聲請，甲持以聲請強制執行，執行法院應如何處理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "4d4a6be888fe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0411", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00088', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-4b605adb', 'sub-judicial-0b5ab5d8-04', NULL, 'essay', '甲受僱於乙網路行銷公司，負責協助客戶公司進行廣告行銷、編輯及社
群媒體維護貼文等工作。甲從網路上搜尋到丙網紅自行拍攝取景，並於
丙之公開部落格「美食天下」刊登，印有浮水印且標示有「版權所有」
的兩張餐廳美食照片，在未經丙同意與授權之情形下，下載後再以裁切
方式移除浮水印，上傳至負責行銷之建案社群媒體，並標註「#來自臺灣
的攻擊」、「#吃個美食再賞屋」、「#有美食的家」、「#網路行銷我最行」等
文字。丙得知後提出告訴。甲辯稱，其目的是為了搭配當時各社群網站
發起分享美食或美景支持臺灣，抗議世界衛生組織的主題標籤活動，且
兩張照片下方皆有標示出處載明「圖片來源：美食天下」，為著作權合理
使用，非有侵權之意。試問依我國著作權法：
甲之行為，該當何民刑事責任？（25 分）
乙之行為，該當何刑事責任？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "03d1a9ebb7a3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0419", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "智慧財產權法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00089', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-4b605adb', 'sub-judicial-0b5ab5d8-04', NULL, 'essay', '甲於民國（下同）104 年 6月 15日以「老洪記及圖」商標，指定使用於
「火鍋店、涮涮鍋店、居酒屋、咖啡屋、茶藝館」之類別，向經濟部智慧
財產局（下稱智慧局）申請註冊，經智慧局核准商標。該商標圖樣為略
經設計之紅色粗體中文「老洪記」，並搭配右方略小紅色圓圈內有印章字
體中文「川味鍋物」所組成。乙知悉後忿忿不平，主張乙自102年 1 月
起經營「洪記麻辣鴛鴦火鍋店」，儘管未註冊商標，但屢獲報章雜誌報導
推薦，頗有知名度。甲曾協助乙處理洪記麻辣鴛鴦火鍋店利潤分配事宜，
並協助店內公關宣傳工作，對店內業務相當熟悉。詎料因細故翻臉後，
甲竟然自行開設火鍋店，並搶註商標。試問，根據我國商標法，乙得為
何主張？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "03d1a9ebb7a3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0419", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "智慧財產權法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00090', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-4b605adb', 'sub-judicial-0b5ab5d8-04', NULL, 'essay', '甲於乙公司擔任籃球鞋開發團隊鞋面技術資深工程師，與公司簽有保密
協議。基於其職位，甲可接觸乙公司為其客戶設計各式籃球鞋樣品及圖
資。甲因友人丙多次懇求，以照相手機拍攝尚未發表上市，儲存於開發
設計中心之限定版籃球鞋照片多張供其私人觀賞。丙後將該等照片以通
訊軟體傳送給友人丁、戊、己一同欣賞，甲知情並叮囑丁、戊、己勿再
外傳且看完要刪除。試問：根據我國營業秘密法，甲之行為是否構成營
業秘密之侵害？（35分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "03d1a9ebb7a3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0419", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "智慧財產權法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00091', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-2c6191fe', 'sub-judicial-0b5ab5d8-05', NULL, 'essay', '甲宗教財團法人於其召開之信徒大會中，決議通過一臨時動議：「逾期未
繳納信徒常年會費者，自動喪失信徒資格，不得異議。」該決議經甲財
團之董監事審議通過，乙等 8名信徒因而喪失信徒會員資格。經查，甲
財團之捐助章程並未規定除名之事由。試問：甲財團將乙等 8名信徒會
員資格除名之行為效力如何？（32 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "9a23a6cfbaf0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與債權、物權編", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00092', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-2c6191fe', 'sub-judicial-0b5ab5d8-05', NULL, 'essay', '甲在自己土地上建築房屋，全部工程由營造商乙承建。乙因同時承包數
項建築工程，恐無法依約完工，乃將甲委建房屋工程轉包給丙，丙完成
房屋建造工作後，未獲報酬。甲入住房屋後，房屋發生嚴重漏水，導致
甲耗資 30萬元之裝潢因漏水而全部毀損。經查，房屋漏水係因丙在頂樓
施工時，防水層覆蓋不足所致。請問：丙就該屋得否請求甲為抵押權之
登記？甲得否依契約責任之規定，逕行向乙請求賠償 30 萬元裝潢費之
損失？（36分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "9a23a6cfbaf0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與債權、物權編", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00093', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-2c6191fe', 'sub-judicial-0b5ab5d8-05', NULL, 'essay', 'A 地原為甲所有，甲在民國 90 年間同意 B 社區無償使用 A 地之一部，
供 B 社區辦公室之用，B 社區內之房屋所有權人共有乙等 30 位。民國
96 年 1 月間甲拋棄 A 地所有權，同年 11 月間中華民國原始取得所有
權，由丙為管理機關。試問：丙在民國 99 年 5 月間依民法第 767 條規
定，向 B 社區與 B 社區之乙等 30 名所有權人請求拆屋還地，是否有理
由？（32分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "9a23a6cfbaf0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與債權、物權編", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00094', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '依司法院大法官解釋，下列何者尚不違背法治國家正當法律程序之要求？', '["以行政文書依法寄存送達完畢時，作為發生送達效力之時點", "稽徵稅捐所發之各種文書，規定對公同共有人中之一人為送達者，其效力及於全體", "於自辦市地重劃案件，未設置適當組織，以審議關於市地重劃範圍之核定程序", "於都市更新程序，未確保利害關係人知悉相關資訊及適時陳述意見之機會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00095', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '依憲法增修條文規定，下列何者有權提出憲法修正案？', '["自由地區選舉人連署", "國民大會", "總統", "立法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL)
